+struct EchoToolHandler;
+
+impl ToolHandler for EchoToolHandler {
+    fn definition(&self) -> Tool {
+        Tool {
+            name: "echo".to_string(),
+            description: Some("Echoes back the input".to_string()),
+            input_schema: json!({
+                "type": "object",
+                "properties": {
+                    "message": { "type": "string" }
+                },
+                "required": ["message"]
+            }),
+            output_schema: None,
+            icon: None,
+            version: Some("1.0.0".to_string()),
+            tags: vec![],
+            annotations: Some(ToolAnnotations::new().read_only(true).idempotent(true)),
+        }
+    }
+
+    fn call(&self, _ctx: &McpContext, arguments: serde_json::Value) -> McpResult<Vec<Content>> {
+        let message = arguments
+            .get("message")
+            .and_then(|v| v.as_str())
+            .unwrap_or("");
+        Ok(vec![Content::Text {
+            text: message.to_string(),
+        }])
+    }
+}
+
+struct CounterToolHandler;
+
+impl ToolHandler for CounterToolHandler {
+    fn definition(&self) -> Tool {
+        Tool {
+            name: "counter".to_string(),
+            description: Some("Returns the call count (not truly stateful, returns arg)".to_string()),
+            input_schema: json!({
+                "type": "object",
+                "properties": {
+                    "value": { "type": "integer" }
+                },
+                "required": ["value"]
+            }),
+            output_schema: None,
+            icon: None,
+            version: None,
+            tags: vec![],
+            annotations: None,
+        }
+    }
+
+    fn call(&self, _ctx: &McpContext, arguments: serde_json::Value) -> McpResult<Vec<Content>> {
+        let value = arguments.get("value").and_then(|v| v.as_i64()).unwrap_or(0);
+        Ok(vec![Content::Text {
+            text: value.to_string(),
+        }])
+    }
+}
+
+struct FailOnDemandToolHandler;
+
+impl ToolHandler for FailOnDemandToolHandler {
+    fn definition(&self) -> Tool {
+        Tool {
+            name: "fail_on_demand".to_string(),
+            description: Some("Fails if 'fail' argument is true".to_string()),
+            input_schema: json!({
+                "type": "object",
+                "properties": {
+                    "fail": { "type": "boolean" },
+                    "message": { "type": "string" }
+                },
+                "required": ["fail"]
+            }),
+            output_schema: None,
+            icon: None,
+            version: None,
+            tags: vec![],
+            annotations: None,
+        }
+    }
+
+    fn call(&self, _ctx: &McpContext, arguments: serde_json::Value) -> McpResult<Vec<Content>> {
+        let should_fail = arguments
+            .get("fail")
+            .and_then(|v| v.as_bool())
+            .unwrap_or(false);
+        if should_fail {
+            let msg = arguments
+                .get("message")
+                .and_then(|v| v.as_str())
+                .unwrap_or("Requested failure");
+            return Err(McpError::tool_error(msg));
+        }
+        Ok(vec![Content::Text {
+            text: "Success".to_string(),
+        }])
+    }
+}
