+// ============================================================================
+// Content type helper for assertions
+// ============================================================================
+
+trait ContentExt {
+    fn as_text(&self) -> Option<&str>;
+}
+
+impl ContentExt for Content {
+    fn as_text(&self) -> Option<&str> {
+        match self {
+            Content::Text { text } => Some(text),
+            _ => None,
+        }
+    }
